#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char c;
        scanf(" %c", &c);
        switch (c) {
            case 'B': case 'b': printf("BattleShip\n"); break;
            case 'C': case 'c': printf("Cruiser\n"); break;
            case 'D': case 'd': printf("Destroyer\n"); break;
            case 'F': case 'f': printf("Frigate\n"); break;
            default: break; // input guaranteed to be valid
        }
    }
    return 0;
}

