code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String line = br.readLine();
            char c = line.charAt(0);
            switch (c) {
                case 'B': case 'b': sb.append("BattleShip\n"); break;
                case 'C': case 'c': sb.append("Cruiser\n"); break;
                case 'D': case 'd': sb.append("Destroyer\n"); break;
                case 'F': case 'f': sb.append("Frigate\n"); break;
                default: break; // input guaranteed to be valid
            }
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def main():
    data = sys.stdin.read().strip().split()  # first token T, then T characters
    if not data:
        return
    T = int(data[0])
    mapping = {
        'B': 'BattleShip', 'b': 'BattleShip',
        'C': 'Cruiser',    'c': 'Cruiser',
        'D': 'Destroyer',  'd': 'Destroyer',
        'F': 'Frigate',    'f': 'Frigate'
    }
    out_lines = []
    for i in range(1, T + 1):
        c = data[i]
        out_lines.append(mapping[c])
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

